1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const survives = (liveNeighborCount: number): boolean =>
10	  liveNeighborCount === 2 || liveNeighborCount === 3;
11	
12	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  const liveKeys = new Set(liveCells.map(keyOf));
19	  const liveNeighborCounts = new Map<string, number>();
20	  for (const cell of liveCells) {
21	    for (const neighbor of neighborsOf(cell)) {
22	      const key = keyOf(neighbor);
23	      liveNeighborCounts.set(key, (liveNeighborCounts.get(key) ?? 0) + 1);
24	    }
25	  }
26	  const survivors = liveCells.filter((cell) =>
27	    survives(liveNeighborCounts.get(keyOf(cell)) ?? 0),
28	  );
29	  const births: Cell[] = [];
30	  for (const [key, count] of liveNeighborCounts) {
31	    if (count === 3 && !liveKeys.has(key)) {
32	      const [x, y] = key.split(",").map(Number);
33	      births.push([x, y]);
34	    }
35	  }
36	  return [...survivors, ...births];
37	}
