1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("live cell with 2 neighbors survives", () => {
15	    // Horizontal blinker: center (1,0) has 2 neighbors (0,0) and (2,0), survives
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("live cell with 4 neighbors dies from overpopulation", () => {
20	    // Plus shape: center (0,0) has 4 live neighbors → dies
21	    const result = nextGeneration([[0, 0], [-1, 0], [1, 0], [0, -1], [0, 1]]);
22	    expect(result).not.toContainEqual([0, 0]);
23	  });
24	  it("dead cell with exactly 3 neighbors becomes alive", () => {
25	    // L-shape: dead cell (1,1) has 3 live neighbors (0,0), (1,0), (0,1)
26	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
27	    expect(result).toContainEqual([1, 1]);
28	  });
29	  it("block pattern (2x2) is stable", () => {
30	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
31	    const result = nextGeneration(block);
32	    expect(result).toHaveLength(4);
33	    expect(result).toEqual(expect.arrayContaining(block));
34	  });
35	  it("blinker oscillates from vertical to horizontal", () => {
36	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
37	    const result = nextGeneration(vertical);
38	    expect(result).toHaveLength(3);
39	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
40	  });
41	  it.todo("handles negative coordinates");
42	});
