type NeighborTally = { cell: Cell; count: number };

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(keyOf));
  const neighborTallies = new Map<string, NeighborTally>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = keyOf(neighbor);
      const existing = neighborTallies.get(key);
      if (existing) existing.count++;
      else neighborTallies.set(key, { cell: neighbor, count: 1 });
    }
  }
  const countAround = (cell: Cell): number =>
    neighborTallies.get(keyOf(cell))?.count ?? 0;
  const survivors = liveCells.filter((cell) => survives(countAround(cell)));
  const births: Cell[] = [];
  for (const [key, { cell, count }] of neighborTallies) {
    if (count === 3 && !liveKeys.has(key)) births.push(cell);
  }
  return [...survivors, ...births];
}
